1: const std = @import("std");
2: 
3: fn defaultOptimize(b: *std.Build) std.builtin.OptimizeMode {
4:     if (b.option(std.builtin.OptimizeMode, "optimize", "Prioritize performance, safety, or binary size")) |mode| {
5:         return mode;
6:     }
7:     if (b.option(bool, "release", "Optimize for end users; defaults to ReleaseSmall") orelse false) {
8:         return .ReleaseSmall;
9:     }
10:     return switch (b.release_mode) {
11:         .off, .any, .small => .ReleaseSmall,
12:         .fast => .ReleaseFast,
13:         .safe => .ReleaseSafe,
14:     };
15: }
16: 
17: pub fn build(b: *std.Build) void {
18:     const optimize = defaultOptimize(b);
19: 
20:     // Match LSMinimumSystemVersion in Info.plist
21:     const target = b.resolveTargetQuery(.{
22:         .os_version_min = .{ .semver = .{ .major = 26, .minor = 0, .patch = 0 } },
23:     });
24: 
25:     // Step 1: Build the Zig static library
26:     const lib = b.addLibrary(.{
27:         .name = "lex",
28:         .linkage = .static,
29:         .root_module = b.createModule(.{
30:             .root_source_file = b.path("src/liblex.zig"),
31:             .target = target,
32:             .optimize = optimize,
33:         }),
34:     });
35: 
36:     // Step 2: Re-pack the archive (Zig master workaround for non-8-byte-aligned members)
37:     const repack = b.addSystemCommand(&.{
38:         "/bin/sh", "-c",
39:         \\tmp=$(mktemp -d) && \
40:         \\cp "$1" "$tmp/lib.a" && \
41:         \\(cd "$tmp" && ar x lib.a && rm lib.a && chmod 644 *.o && /usr/bin/ar rcs lib.a *.o) && \
42:         \\cp "$tmp/lib.a" "$1" && \
43:         \\rm -rf "$tmp"
44:         ,
45:         "--",
46:     });
47:     repack.addArtifactArg(lib);
48:     repack.has_side_effects = true;
49: 
50:     // Derive Swift target triple from host arch + macOS deployment target
51:     const arch = target.result.cpu.arch;
52:     const swift_arch: []const u8 = switch (arch) {
53:         .aarch64 => "arm64",
54:         .x86_64 => "x86_64",
55:         else => @panic("unsupported host architecture for macOS build"),
56:     };
57:     const swift_target = b.fmt("{s}-apple-macosx26.0", .{swift_arch});
58: 
59:     // Step 3: Ensure the app bundle executable directory exists.
60:     const mkdir_app_bin = b.addSystemCommand(&.{
61:         "/bin/mkdir", "-p", "macos/Lex.app/Contents/MacOS",
62:     });
63:     mkdir_app_bin.has_side_effects = true;
64: 
65:     // Step 4: Compile Swift and link with the Zig library
66:     const swiftc = b.addSystemCommand(&.{
67:         "swiftc",
68:         "macos/Lex.swift",
69:         "-import-objc-header",
70:         "src/liblex.h",
71:         "-target",
72:     });
73:     swiftc.addArg(swift_target);
74:     swiftc.addPrefixedDirectoryArg("-L", lib.getEmittedBinDirectory());
75:     swiftc.addArgs(&.{"-llex"});
76:     swiftc.addArgs(&.{ "-o", "macos/Lex.app/Contents/MacOS/Lex" });
77:     swiftc.step.dependOn(&repack.step);
78:     swiftc.step.dependOn(&mkdir_app_bin.step);
79:     swiftc.has_side_effects = true;
80: 
81:     // Step 5: Strip local symbols before codesigning
82:     const strip = b.addSystemCommand(&.{
83:         "strip", "-x", "macos/Lex.app/Contents/MacOS/Lex",
84:     });
85:     strip.step.dependOn(&swiftc.step);
86:     strip.has_side_effects = true;
87: 
88:     // Step 6: Ad-hoc codesign
89:     const codesign = b.addSystemCommand(&.{
90:         "codesign", "-f", "-s", "-", "macos/Lex.app",
91:     });
92:     codesign.step.dependOn(&strip.step);
93:     codesign.has_side_effects = true;
94: 
95:     // Wire into default install step
96:     b.getInstallStep().dependOn(&codesign.step);
97: 
98:     // `zig build run` — open the app
99:     const run = b.addSystemCommand(&.{ "open", "macos/Lex.app" });
100:     run.step.dependOn(b.getInstallStep());
101:     const run_step = b.step("run", "Build and open Lex.app");
102:     run_step.dependOn(&run.step);
103: }
